-- PostgreSQL Data Export for ACOS
BEGIN;

SET CONSTRAINTS ALL DEFERRED;

-- Data for table: users
SELECT setval(pg_get_serial_sequence('"users"', 'id'), coalesce(max(id), 1)) FROM "users";

-- Data for table: categories
SELECT setval(pg_get_serial_sequence('"categories"', 'id'), coalesce(max(id), 1)) FROM "categories";

-- Data for table: brands
SELECT setval(pg_get_serial_sequence('"brands"', 'id'), coalesce(max(id), 1)) FROM "brands";

-- Data for table: suppliers
SELECT setval(pg_get_serial_sequence('"suppliers"', 'id'), coalesce(max(id), 1)) FROM "suppliers";

-- Data for table: assets
SELECT setval(pg_get_serial_sequence('"assets"', 'id'), coalesce(max(id), 1)) FROM "assets";

-- Data for table: products
SELECT setval(pg_get_serial_sequence('"products"', 'id'), coalesce(max(id), 1)) FROM "products";

-- Data for table: product_assets
SELECT setval(pg_get_serial_sequence('"product_assets"', 'id'), coalesce(max(id), 1)) FROM "product_assets";

-- Data for table: product_variants
SELECT setval(pg_get_serial_sequence('"product_variants"', 'id'), coalesce(max(id), 1)) FROM "product_variants";

COMMIT;
